// Fetch pending reminders from Supabase
const SUPABASE_URL = "https://inhyrrjidhzrbqecnptn.supabase.co";
const SERVICE_KEY = $env.N8N_SUPABASE_SERVICE_KEY;

let reminders;
try {
    reminders = await this.helpers.httpRequest({
        method: "POST",
        url: SUPABASE_URL + "/rest/v1/rpc/get_pending_reminders",
        headers: {
            "apikey": SERVICE_KEY,
            "Authorization": "Bearer " + SERVICE_KEY,
            "Content-Type": "application/json"
        },
        body: {},
        json: true
    });
} catch(e) {
    reminders = [];
}

if (!Array.isArray(reminders) || reminders.length === 0) {
    return [{ json: { no_reminders: true, count: 0 } }];
}

// Return each reminder as separate item for split processing
return reminders.map(r => ({
    json: {
        appointment_id: r.appointment_id,
        clinic_id: r.clinic_id,
        clinic_name: r.clinic_name,
        patient_name: r.patient_name,
        phone: r.phone,
        service: r.service,
        start_time: r.start_time,
        chatwoot_inbox_id: r.chatwoot_inbox_id
    }
}));

const t   = new Date($json.start_time);
const dt  = t.toLocaleDateString('es-PE', { weekday:'long', day:'numeric', month:'long', hour:'2-digit', minute:'2-digit', hour12:true });
const nom = $json.patient_name || 'paciente';
const cli = $json.clinic_name  || 'la clinica';
const svc = $json.service      || 'Consulta';

const msg = [
  '*Recordatorio de Cita*',
  '',
  'Hola ' + nom + ',',
  '',
  'Le confirmamos su proxima cita:',
  'Clinica: *' + cli + '*',
  'Manana: *' + dt + '*',
  'Servicio: *' + svc + '*',
  '',
  'Para *confirmar* su asistencia, responda *1*',
  'Para *reprogramar*, responda *2*',
  '',
  '_SofIA - Asistente automatico de ' + cli + '_'
].join('\n');

return [{ json: { ...$json, reminder_message: msg } }];

// Mark reminder as sent in Supabase
const SUPABASE_URL = "https://inhyrrjidhzrbqecnptn.supabase.co";
const SERVICE_KEY = $env.N8N_SUPABASE_SERVICE_KEY;

try {
    await this.helpers.httpRequest({
        method: "POST",
        url: SUPABASE_URL + "/rest/v1/rpc/mark_reminder_sent",
        headers: {
            "apikey": SERVICE_KEY,
            "Authorization": "Bearer " + SERVICE_KEY,
            "Content-Type": "application/json"
        },
        body: {
            p_appointment_id: $json.appointment_id,
            p_status: "sent",
            p_error: null
        },
        json: true
    });
} catch(e) {
    // Log error but continue
}

return [{ json: { ...$json, reminder_sent: true } }];

